  '#8B5CF6',
  'Estúdio Bela e Arte — Salão e Barbearia em Porto Alegre',
  'Cortes, coloração e tratamentos capilares com hora marcada.',
  '{"hero":{"titulo":"Estúdio Bela & Arte","subtitulo":"Seu espaço de beleza e cuidado pessoal em Porto Alegre. Cortes modernos, coloração profissional e tratamentos exclusivos.","cta_texto":"Agendar pelo WhatsApp","cta_link":"https://wa.me/5551999990001","bg_image_url":"https://images.unsplash.com/photo-1560066984-138dadb4c035?w=1200&q=80"},"sobre":{"texto":"Somos um estúdio de beleza completo, atendendo homens e mulheres há mais de 8 anos em Porto Alegre. Nossa equipe é formada por profissionais certificados, apaixonados por transformar e realçar a sua beleza natural.\n\nAqui você encontra desde o corte clássico até as técnicas mais modernas de coloração e tratamento capilar.","foto_url":"https://images.unsplash.com/photo-1522337360788-8b13dee7a37e?w=800&q=80"},"servicos":[{"id":"s1","nome":"Corte Feminino","descricao":"Corte personalizado com lavagem e secagem incluídas.","preco":"A partir de R$80","icone":"Scissors"},{"id":"s2","nome":"Coloração","descricao":"Técnicas modernas: balayage, ombré, luzes e coloração global.","preco":"A partir de R$150","icone":"Star"},{"id":"s3","nome":"Corte Masculino","descricao":"Corte moderno com acabamento de barba incluso.","preco":"A partir de R$55","icone":"Scissors"},{"id":"s4","nome":"Tratamento Capilar","descricao":"Hidratação profunda, reconstrução e cronograma capilar.","preco":"A partir de R$120","icone":"Heart"},{"id":"s5","nome":"Manicure & Pedicure","descricao":"Esmaltação simples, gel, fibra e nail art.","preco":"A partir de R$45","icone":"Zap"},{"id":"s6","nome":"Sobrancelha","descricao":"Design, micropigmentação e laminação de sobrancelhas.","preco":"A partir de R$40","icone":"Star"}],"galeria":[{"id":"g1","url":"https://images.unsplash.com/photo-1595476108010-b4d1f102b1b1?w=600&q=80","caption":"Coloração balayage"},{"id":"g2","url":"https://images.unsplash.com/photo-1582095133179-bfd08e2979b2?w=600&q=80","caption":"Corte feminino"},{"id":"g3","url":"https://images.unsplash.com/photo-1503951914875-452162b0f3f1?w=600&q=80","caption":"Barbearia"},{"id":"g4","url":"https://images.unsplash.com/photo-1562322140-8baeececf3df?w=600&q=80","caption":"Tratamento capilar"},{"id":"g5","url":"https://images.unsplash.com/photo-1519014816548-bf5fe059798b?w=600&q=80","caption":"Manicure"},{"id":"g6","url":"https://images.unsplash.com/photo-1570172619644-dfd03ed5d881?w=600&q=80","caption":"Ambiente do salão"}],"contato":{"telefone":"(51) 3333-0001","whatsapp":"(51) 99999-0001","email":"contato@estudiobela.com.br","endereco":"Rua da Praia, 180 - Centro Histórico\nPorto Alegre, RS - CEP 90010-060","maps_url":""},"redes":{"instagram":"@estudiobela.poa","facebook":"EstudioBelaArte","tiktok":"@estudiobela","youtube":"","linkedin":""},"horarios":[{"dia":"Segunda","abre":"09:00","fecha":"19:00","fechado":false},{"dia":"Terça","abre":"09:00","fecha":"19:00","fechado":false},{"dia":"Quarta","abre":"09:00","fecha":"19:00","fechado":false},{"dia":"Quinta","abre":"09:00","fecha":"20:00","fechado":false},{"dia":"Sexta","abre":"09:00","fecha":"20:00","fechado":false},{"dia":"Sábado","abre":"08:00","fecha":"17:00","fechado":false},{"dia":"Domingo","abre":"","fecha":"","fechado":true}],"depoimentos":[{"id":"d1","nome":"Juliana Ferreira","texto":"Melhor salão que já frequentei! A Cíntia é incrível com coloração, ficou exatamente como eu queria. Ambiente super agradável.","rating":5},{"id":"d2","nome":"Carlos Mendes","texto":"Corte e barba impecáveis. Atendimento rápido e de qualidade. Virei cliente fixo!","rating":5},{"id":"d3","nome":"Patrícia Lima","texto":"Fiz hidratação e meu cabelo ficou irreconhecível (no bom sentido!). Super recomendo o cronograma capilar.","rating":5}],"cta_flutuante":{"tipo":"whatsapp","valor":"(51) 99999-0001"}}'::jsonb,
  1247, 89
) ON CONFLICT (slug) DO NOTHING;

INSERT INTO websites (
