  'light',
  '#0891B2',
  'Clínica Essence — Estética e Bem-Estar em São Paulo',
  'Tratamentos estéticos avançados para rosto e corpo. Agende sua avaliação gratuita.',
  '{"hero":{"titulo":"Clínica Essence","subtitulo":"Tratamentos estéticos avançados para realçar sua beleza com segurança e ciência. Agende uma avaliação gratuita.","cta_texto":"Agendar avaliação gratuita","cta_link":"https://wa.me/5511999990002","bg_image_url":"https://images.unsplash.com/photo-1540555700478-4be289fbecef?w=1200&q=80"},"sobre":{"texto":"A Clínica Essence nasceu da paixão por transformar vidas através da estética de alta performance. Localizada no Itaim Bibi, São Paulo, atendemos clientes que buscam resultados reais com tratamentos seguros e baseados em evidências.\n\nNossa equipe é formada por biomédicas, esteticistas e dermatologistas parceiros, todos dedicados ao seu bem-estar.","foto_url":"https://images.unsplash.com/photo-1629909613654-28e377c37b09?w=800&q=80"},"servicos":[{"id":"s1","nome":"Limpeza de Pele Profunda","descricao":"Protocolo completo com peeling enzimático, extração e máscara calmante.","preco":"R$180","icone":"Heart"},{"id":"s2","nome":"Botox & Preenchimento","descricao":"Aplicação de toxina botulínica e ácido hialurônico com médico parceiro.","preco":"Consultar","icone":"Star"},{"id":"s3","nome":"Radiofrequência","descricao":"Tratamento para flacidez facial e corporal com resultados progressivos.","preco":"R$250 / sessão","icone":"Zap"},{"id":"s4","nome":"Drenagem Linfática","descricao":"Técnica manual para redução de inchaço, celulite e pós-cirúrgico.","preco":"R$130 / sessão","icone":"Heart"},{"id":"s5","nome":"Luz Pulsada (IPL)","descricao":"Tratamento para manchas, pelos e rejuvenescimento da pele.","preco":"R$350 / sessão","icone":"Zap"},{"id":"s6","nome":"Massagem Relaxante","descricao":"60 minutos de relaxamento profundo com óleos essenciais importados.","preco":"R$160","icone":"Heart"}],"galeria":[{"id":"g1","url":"https://images.unsplash.com/photo-1570172619644-dfd03ed5d881?w=600&q=80","caption":"Tratamento facial"},{"id":"g2","url":"https://images.unsplash.com/photo-1515377905703-c4788e51af15?w=600&q=80","caption":"Espaço relaxante"},{"id":"g3","url":"https://images.unsplash.com/photo-1552693673-1bf958298935?w=600&q=80","caption":"Radiofrequência"},{"id":"g4","url":"https://images.unsplash.com/photo-1596755094514-f87e34085b2c?w=600&q=80","caption":"Limpeza de pele"}],"contato":{"telefone":"(11) 3333-0002","whatsapp":"(11) 99999-0002","email":"agendamento@clinicaessence.com.br","endereco":"Av. Brigadeiro Faria Lima, 2232 - Itaim Bibi\nSão Paulo, SP - CEP 01452-000","maps_url":""},"redes":{"instagram":"@clinicaessence.sp","facebook":"ClinicaEssenceSP","tiktok":"@clinicaessence","youtube":"","linkedin":"clinica-essence"},"horarios":[{"dia":"Segunda","abre":"08:00","fecha":"18:00","fechado":false},{"dia":"Terça","abre":"08:00","fecha":"18:00","fechado":false},{"dia":"Quarta","abre":"08:00","fecha":"20:00","fechado":false},{"dia":"Quinta","abre":"08:00","fecha":"20:00","fechado":false},{"dia":"Sexta","abre":"08:00","fecha":"18:00","fechado":false},{"dia":"Sábado","abre":"09:00","fecha":"14:00","fechado":false},{"dia":"Domingo","abre":"","fecha":"","fechado":true}],"depoimentos":[{"id":"d1","nome":"Renata Souza","texto":"Fiz radiofrequência por 10 sessões e o resultado foi incrível! Minha pele ficou muito mais firme. A equipe é super atenciosa.","rating":5},{"id":"d2","nome":"Mariana Costa","texto":"Melhor clínica de SP! A limpeza de pele é maravilhosa e o ambiente é super aconchegante. Já indiquei para todas as amigas.","rating":5},{"id":"d3","nome":"Fernanda Alves","texto":"Fiz botox aqui e adorei o resultado. Natural e duradouro. Profissionais muito competentes e cuidadosos.","rating":5}],"cta_flutuante":{"tipo":"whatsapp","valor":"(11) 99999-0002"}}'::jsonb,
  2891, 134
) ON CONFLICT (slug) DO NOTHING;

