  '#D97706',
  'Casa e Estilo — Loja de Variedades e Presentes em Belo Horizonte',
  'Decoração, presentes e utilidades para sua casa. Encontre o item perfeito para cada ocasião.',
  '{"hero":{"titulo":"Casa & Estilo","subtitulo":"Sua loja de decoração, presentes e utilidades em Belo Horizonte. Encontre o presente perfeito para cada ocasião.","cta_texto":"Falar no WhatsApp","cta_link":"https://wa.me/5531999990003","bg_image_url":"https://images.unsplash.com/photo-1556742049-0cfed4f6a45d?w=1200&q=80"},"sobre":{"texto":"A Casa & Estilo nasceu em 2015 com a missão de trazer produtos de qualidade, design e afeto para os lares de Belo Horizonte. Somos uma loja de variedades com curadoria especial, selecionando peças que combinam funcionalidade e beleza.\n\nEncontre conosco itens de decoração, utilidades domésticas, papelaria, presentes para todas as idades e muito mais.","foto_url":"https://images.unsplash.com/photo-1441986300917-64674bd600d8?w=800&q=80"},"servicos":[{"id":"s1","nome":"Decoração & Presentes","descricao":"Vasos, quadros, velas, porta-retratos e itens de decoração para todos os estilos.","preco":"A partir de R$25","icone":"Home"},{"id":"s2","nome":"Papelaria Premium","descricao":"Cadernos, canetas, planejadores e itens de escritório com design exclusivo.","preco":"A partir de R$15","icone":"FileText"},{"id":"s3","nome":"Cesta de Presentes","descricao":"Monte sua cesta personalizada para aniversários, casamentos e datas especiais.","preco":"A partir de R$89","icone":"Heart"},{"id":"s4","nome":"Utilidades Domésticas","descricao":"Organizadores, porta-temperos, jogos de cozinha e itens práticos para o dia a dia.","preco":"A partir de R$19","icone":"Home"},{"id":"s5","nome":"Infantil & Brinquedos","descricao":"Brinquedos educativos, pelúcias e itens de quarto para crianças.","preco":"A partir de R$35","icone":"Star"},{"id":"s6","nome":"Embalagem para Presente","descricao":"Embalagem profissional com papel de seda, laço e cartão personalizado.","preco":"R$8","icone":"Heart"}],"galeria":[{"id":"g1","url":"https://images.unsplash.com/photo-1484101403633-562f891dc89a?w=600&q=80","caption":"Decoração sala"},{"id":"g2","url":"https://images.unsplash.com/photo-1513519245088-0e12902e5a38?w=600&q=80","caption":"Presentes"},{"id":"g3","url":"https://images.unsplash.com/photo-1491553895911-0055eca6402d?w=600&q=80","caption":"Papelaria"},{"id":"g4","url":"https://images.unsplash.com/photo-1556742031-c6961e8560b0?w=600&q=80","caption":"Cestas personalizadas"},{"id":"g5","url":"https://images.unsplash.com/photo-1586023492125-27b2c045efd7?w=600&q=80","caption":"Decoração quarto"}],"contato":{"telefone":"(31) 3333-0003","whatsapp":"(31) 99999-0003","email":"contato@casaestilo.com.br","endereco":"Rua dos Carijós, 450 - Centro\nBelo Horizonte, MG - CEP 30120-060","maps_url":""},"redes":{"instagram":"@casaestilo.bh","facebook":"CasaEstiloBH","tiktok":"","youtube":"","linkedin":""},"horarios":[{"dia":"Segunda","abre":"09:00","fecha":"18:00","fechado":false},{"dia":"Terça","abre":"09:00","fecha":"18:00","fechado":false},{"dia":"Quarta","abre":"09:00","fecha":"18:00","fechado":false},{"dia":"Quinta","abre":"09:00","fecha":"18:00","fechado":false},{"dia":"Sexta","abre":"09:00","fecha":"18:00","fechado":false},{"dia":"Sábado","abre":"09:00","fecha":"16:00","fechado":false},{"dia":"Domingo","abre":"","fecha":"","fechado":true}],"depoimentos":[{"id":"d1","nome":"Isabela Rodrigues","texto":"Loja incrível! Encontro sempre presentes originais e com ótimo preço. A embalagem de presente é linda, economiza muito tempo!","rating":5},{"id":"d2","nome":"Paulo Henrique","texto":"Comprei vários itens de decoração para meu apartamento novo. Tudo com qualidade ótima e os preços são justos. Adorei!","rating":5},{"id":"d3","nome":"Amanda Fonseca","texto":"As cestas de presente são maravilhosas! Já comprei para várias ocasiões e sempre recebo elogios. Super recomendo.","rating":5}],"cta_flutuante":{"tipo":"whatsapp","valor":"(31) 99999-0003"}}'::jsonb,
  1653, 97
) ON CONFLICT (slug) DO NOTHING;